Hi. I would like links to related resources instead of just the id. Are there anyway to configure this? Meanwhile i made the following monkey patch:
```
def _sanitize_value(value):
    if isinstance(value.__class__, DeclarativeMeta):
        resource = _get_resource(value)
        if config.DOMAIN[resource].get('self_link', None):
            return _get_uri(value)
        else:
            return _get_id(value)
    elif isinstance(value, collections.Mapping):
        return dict([(k, _sanitize_value(v)) for k, v in value.items()])
    elif isinstance(value, collections.MutableSequence):
        return [_sanitize_value(v) for v in value]
    elif isinstance(value, collections.Set):
        return set(_sanitize_value(v) for v in value)
    else:
        return copy.copy(value)

eve_sqlalchemy.utils._sanitize_value = _sanitize_value

def _get_uri(obj):
    resource = _get_resource(obj)
    return config.DOMAIN[resource]['url'] + '/' + str(_get_id(obj))
```

